# Matches the first fenced code block, e.g. ```json ... ``` or ``` ... ```.
_CODE_FENCE_RE = re.compile(r"```[ \t]*[A-Za-z0-9_+-]*[ \t]*\r?\n(.*?)```", re.DOTALL)


def _extract_code_fence(text: str) -> str | None:
    """Extract and trim the content of the first fenced code block in `text`, if any."""
    match = _CODE_FENCE_RE.search(text)
    if match is None:
        return None
    return match.group(1).strip()


def _split_line_comment(line: str) -> tuple[str, str | None]:
    """Split a line into (code, comment) around the first unquoted `#`."""
    in_string = False
    escape = False
    for i, ch in enumerate(line):
        if escape:
            escape = False
            continue
        if ch == "\\":
            escape = True
            continue
        if ch == '"':
            in_string = not in_string
        elif ch == "#" and not in_string:
            return line[:i], line[i + 1 :].strip()
    return line, None


